		get_contacts: IDL.Func([], [GetContactsResult]),
		get_exchange_rate: IDL.Func([TokenId], [IDL.Opt(ExchangeRate)]),
		get_exchange_rates: IDL.Func(
			[IDL.Vec(TokenId)],
			[IDL.Vec(IDL.Tuple(TokenId, IDL.Opt(ExchangeRate)))]
		),
